import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/** ====== Helpers ====== **/
const TYPE_MAP = [
    { label: "Thi công", value: "CONSTRUCTION" },
    { label: "Dịch vụ", value: "SERVICE" },
];

const STATUS_MAP = [
    { label: "Đang thực hiện", value: "PENDING" },
    { label: "Hoàn tất", value: "COMPLETED" },
    { label: "Hủy", value: "CANCELLED" },
];

const findLabel = (list, v) => list.find((x) => x.value === v)?.label || v || "-";
const fmtMoney = (n) => (n ?? 0).toLocaleString("vi-VN", { maximumFractionDigits: 0 });
const parseMoney = (s) => {
    if (typeof s === "number") return s;
    if (!s) return 0;
    const digits = String(s).replace(/[^\d]/g, "");
    return Number(digits || 0);
};
const toISO = (d) => {
    if (!d) return "";
    if (/^\d{4}-\d{2}-\d{2}$/.test(d)) return d;
    const m = String(d).match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (m) return `${m[3]}-${m[2]}-${m[1]}`;
    try {
        const dt = new Date(d);
        if (!isNaN(dt)) return dt.toISOString().slice(0, 10);
    } catch {}
    return "";
};
function useDebounce(v, delay = 450) {
    const [val, setVal] = useState(v);
    useEffect(() => {
        const t = setTimeout(() => setVal(v), delay);
        return () => clearTimeout(t);
    }, [v, delay]);
    return val;
}
const hasRole = (user, roles) => {
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object") {
            ["role", "name", "authority", "code"].forEach((k) => x[k] && S.add(String(x[k]).toUpperCase()));
            ["roles", "authorities"].forEach((k) => add(x[k]));
        }
    };
    add(user?.role); add(user?.roles); add(user?.authorities);
    return roles.some((r) => S.has(r));
};
function isSaleUser(u) {
    const bag = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return bag.add(x.toUpperCase());
        if (typeof x === "object") {
            ["role", "name", "authority", "code"].forEach((k) => u[k] && bag.add(String(u[k]).toUpperCase()));
            ["roles", "authorities"].forEach((k) => add(u[k]));
        }
    };
    add(u.roles); add(u.authorities); add(u.role);
    for (const v of bag) if (v.includes("SALE")) return true;
    return false;
}

/** ====== Page ====== **/
export default function Contracts() {
    const { user } = useAuth();
    const canEdit = hasRole(user, ["ADMIN"]); // chỉ ADMIN được thao tác

    const [rows, setRows] = useState([]);
    const [customers, setCustomers] = useState([]);
    const [sales, setSales] = useState([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [q, setQ] = useState("");
    const dq = useDebounce(q);
    const [type, setType] = useState("");
    const [status, setStatus] = useState("");
    const [from, setFrom] = useState("");
    const [to, setTo] = useState("");

    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);

    const [form, setForm] = useState({
        contractCode: "",
        title: "",
        customerId: "",
        salesId: "",
        totalAmount: "",
        signedDate: "",
        dueDate: "",
        contractType: "CONSTRUCTION",
        status: "PENDING",
    });

    useEffect(() => { loadAll(); /* eslint-disable-next-line */ }, [dq, type, status, from, to]);
    useEffect(() => { loadSales(); }, []);

    async function loadAll() {
        setLoading(true);
        const params = {
            q: dq || undefined,
            type: type || undefined,
            status: status || undefined,
            from: toISO(from) || undefined,
            to: toISO(to) || undefined,
            page: 0, size: 50, sort: "id,desc",
        };
        const [contractsRes, customersRes] = await Promise.allSettled([
            api.get("/api/contracts", { params }),
            api.get("/api/customers", { params: { page: 0, size: 100, sort: "name,asc" } }),
        ]);

        if (contractsRes.status === "fulfilled") {
            const data = contractsRes.value?.data;
            const list = Array.isArray(data) ? data : data?.content || [];
            setRows(list.map((x) => ({
                id: x.id, contractCode: x.contractCode, title: x.title, contractType: x.contractType,
                customerId: x.customerId, customerName: x.customerName,
                salesId: x.salesId || x.saleId || x.sales?.id || x.sale?.id,
                salesName: x.salesName || x.saleName || x.sales?.fullName || x.sales?.name || x.sales?.username
                    || x.sale?.fullName || x.sale?.name || x.sale?.username || "",
                signedDate: x.signedDate, dueDate: x.dueDate,
                totalAmount: x.totalAmount, paidAmount: x.paidAmount, remainingAmount: x.remainingAmount,
                status: x.status,
            })));
        } else {
            console.warn("Contracts load failed:", contractsRes.reason);
            setRows([]); // không giữ dữ liệu cũ nếu lỗi
        }

        if (customersRes.status === "fulfilled") {
            const data = customersRes.value?.data;
            const list = Array.isArray(data) ? data : data?.content || [];
            setCustomers(list.map((c) => ({ id: c.id, name: c.name })));
        } else {
            console.warn("Customers load failed:", customersRes.reason);
        }
        setLoading(false);
    }

    async function loadSales() {
        try {
            const tries = [
                { url: "/api/users", params: { page: 0, size: 1000, sort: "id,asc" } },
                { url: "/api/users", params: { role: "SALES", page: 0, size: 1000 } },
                { url: "/api/users/sales", params: {} },
            ];
            let users = [];
            for (const t of tries) {
                try {
                    const { data } = await api.get(t.url, { params: t.params });
                    users = Array.isArray(data) ? data : data?.content || [];
                    if (users.length) break;
                } catch {}
            }
            const saleUsers = users.filter(isSaleUser);
            setSales(saleUsers.map((u) => ({
                id: u.id, name: u.fullName || u.name || u.username || `User #${u.id}`,
            })));
        } catch (e) {
            console.warn("Không lấy được danh sách SALE:", e);
            setSales([]);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({
            contractCode: autoCode(),
            title: "", customerId: "", salesId: "", totalAmount: "",
            signedDate: todayStr(), dueDate: "",
            contractType: "CONSTRUCTION", status: "PENDING",
        });
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            contractCode: row.contractCode || "", title: row.title || "",
            customerId: row.customerId || "",
            salesId: row.salesId ? String(row.salesId) : "",
            totalAmount: fmtMoney(row.totalAmount || 0),
            signedDate: toISO(row.signedDate) || "",
            dueDate: toISO(row.dueDate) || "",
            contractType: row.contractType || "CONSTRUCTION",
            status: row.status || "PENDING",
        });
        setShow(true);
    }

    function clean(obj) {
        const out = {};
        Object.entries(obj).forEach(([k, v]) => { if (v !== undefined) out[k] = v; });
        return out;
    }

    /** ====== SAVE (validate + fallback + enum SERVICE variants) ====== **/
    async function save(e) {
        e.preventDefault();
        try {
            const title = (form.title || "").trim();
            if (!title) return alert("Vui lòng nhập Tiêu đề.");
            if (!editing && !form.customerId) return alert("Vui lòng chọn Khách hàng.");
            if (!form.salesId) return alert("Vui lòng chọn Phụ trách (Sale).");

            const total = parseMoney(form.totalAmount);
            if (!total || total <= 0) return alert("Giá trị hợp đồng phải lớn hơn 0.");

            const signed = toISO(form.signedDate);
            if (!signed) return alert("Ngày ký không hợp lệ (yyyy-MM-dd).");
            const due = toISO(form.dueDate) || null;
            if (due && new Date(due) < new Date(signed)) return alert("Ngày hết hạn phải >= Ngày ký.");

            const saleIdNum = form.salesId ? Number(form.salesId) : undefined;

            const enumCandidates =
                form.contractType === "SERVICE"
                    ? ["SERVICE", "SERVICES", "SERVICE_CONTRACT"]
                    : ["CONSTRUCTION"];

            if (editing) {
                const payload = clean({
                    contractCode: form.contractCode?.trim() || null,
                    title,
                    contractType: form.contractType,
                    signedDate: signed,
                    dueDate: due,
                    totalAmount: total,
                    status: form.status || "PENDING",
                    salesId: saleIdNum,
                    saleId: saleIdNum,
                });
                try {
                    await api.patch(`/api/contracts/${editing.id}`, payload);
                } catch {
                    await api.put(`/api/contracts/${editing.id}`, payload);
                }
            } else {
                let lastErr = null;
                for (const ct of enumCandidates) {
                    const base = clean({
                        contractCode: form.contractCode?.trim() || undefined,
                        title,
                        contractType: ct,
                        customerId: Number(form.customerId),
                        signedDate: signed,
                        dueDate: due,
                        totalAmount: total,
                        status: "PENDING",
                        salesId: saleIdNum,
                        saleId: saleIdNum,
                    });

                    const attempts = [base, { ...base }, { ...base }];
                    delete attempts[1].status;
                    attempts[2] = {
                        contractCode: base.contractCode,
                        title,
                        contractType: ct,
                        customerId: Number(form.customerId),
                        signedDate: signed,
                        dueDate: due,
                        totalAmount: total,
                        saleId: saleIdNum,
                    };

                    for (const payload of attempts) {
                        try {
                            await api.post("/api/contracts", payload);
                            lastErr = null;
                            break;
                        } catch (err) {
                            lastErr = err;
                            const s = err?.response?.status || 0;
                            if (![400, 409, 415, 422].includes(s)) break;
                            if (s === 409) throw err;
                        }
                    }
                    if (!lastErr) break;
                }
                if (lastErr) throw lastErr;
            }

            setShow(false);
            await loadAll();
        } catch (err) {
            const res = err?.response;
            console.error("Save contract error:", res || err);

            const data = res?.data;
            let msgs = [];
            const push = (m) => { if (!m) return; Array.isArray(m) ? m.forEach(push) : msgs.push(String(m)); };
            if (typeof data === "string") push(data);
            if (data && typeof data === "object") {
                if (data.errors) data.errors.forEach((e) => push(e.defaultMessage || e.message || e.code));
                if (data.fieldErrors) data.fieldErrors.forEach((e) => push(e.defaultMessage || `${e.field}: ${e.message || e.code}`));
                if (data.violations) data.violations.forEach((v) => push(v.message || `${v.field}: ${v.message}`));
                push(data.message); push(data.error); push(data.details);
                if (data.cause?.message) push(data.cause.message);
            }
            let msg = msgs.filter(Boolean).join("\n");
            if (!msg) {
                if (res?.status === 409) msg = "Mã hợp đồng đã tồn tại.";
                else if (res?.status) msg = `Lưu hợp đồng thất bại (HTTP ${res.status})`;
                else msg = "Lưu hợp đồng thất bại";
            }
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xóa hợp đồng ${row.contractCode}?`)) return;
        try {
            await api.delete(`/api/contracts/${row.id}`);
            await loadAll();
        } catch (err) {
            const res = err?.response;
            const data = res?.data;
            const msg =
                data?.message || data?.error || (typeof data === "string" ? data : "") ||
                `Xóa hợp đồng thất bại (HTTP ${res?.status || "?"})`;
            console.error("Delete contract error:", res || err);
            alert(msg);
        }
    }

    const customerOptions = useMemo(() => customers.map((c) => ({ value: String(c.id), label: c.name })), [customers]);
    const salesOptions = useMemo(() => sales.map((s) => ({ value: String(s.id), label: s.name })), [sales]);

    return (
        <div className="space-y-8">
            {/* Toolbar */}
            <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-3">
                <div>
                    <h2 className="text-lg font-semibold text-slate-900">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Tìm kiếm, lọc và quản lý hợp đồng.</p>
                </div>

                <div className="flex flex-wrap items-end gap-2">
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                        <input
                            className="w-80 px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            placeholder="Mã/tiêu đề/KH/NVKD…"
                            value={q}
                            onChange={(e) => setQ(e.target.value)}
                        />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Loại HĐ</label>
                        <select className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={type} onChange={(e) => setType(e.target.value)}>
                            <option value="">Tất cả</option>
                            {TYPE_MAP.map((t) => <option key={t.value} value={t.value}>{t.label}</option>)}
                        </select>
                    </div>
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                        <select className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={status} onChange={(e) => setStatus(e.target.value)}>
                            <option value="">Tất cả</option>
                            {STATUS_MAP.map((s) => <option key={s.value} value={s.value}>{s.label}</option>)}
                        </select>
                    </div>
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Từ ngày</label>
                        <input type="date" className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={from} onChange={(e) => setFrom(e.target.value)} />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Đến ngày</label>
                        <input type="date" className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={to} onChange={(e) => setTo(e.target.value)} />
                    </div>

                    {canEdit && (
                        <button onClick={openCreate} className="ml-auto px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                            Thêm hợp đồng
                        </button>
                    )}
                </div>
            </div>

            {/* List */}
            <div className="grid grid-cols-1 2xl:grid-cols-2 gap-8">
                {loading ? (
                    <div className="col-span-full text-slate-500">Đang tải…</div>
                ) : rows.length === 0 ? (
                    <div className="col-span-full text-slate-500">Không có hợp đồng phù hợp</div>
                ) : (
                    rows.map((c) => (
                        <div key={c.id} className="rounded-3xl border border-indigo-100 bg-white p-6 shadow-md hover:shadow-lg transition h-full flex flex-col">
                            <div className="flex items-start justify-between gap-4">
                                <div className="text-lg md:text-xl font-semibold text-slate-900 truncate">{c.contractCode || "(Không mã)"}</div>
                                <span className="text-xs px-2 py-0.5 rounded-full bg-amber-100 text-amber-700 shrink-0">
                  {findLabel(STATUS_MAP, c.status)}
                </span>
                            </div>
                            <div className="mt-2 text-base text-slate-600">{c.title || "—"}</div>
                            <div className="mt-1 text-sm text-slate-500">
                                {findLabel(TYPE_MAP, c.contractType)} • Kh: {c.customerName || "—"}
                                {c.salesName ? <> • Sale: {c.salesName}</> : null}
                            </div>
                            <div className="mt-4 grid grid-cols-1 sm:grid-cols-3 gap-3">
                                <div className="rounded-xl bg-slate-50 px-4 py-3">
                                    <div className="text-xs text-slate-500">Giá trị</div>
                                    <div className="font-semibold tabular-nums tracking-tight text-base whitespace-nowrap">{fmtMoney(c.totalAmount)} đ</div>
                                </div>
                                <div className="rounded-xl bg-slate-50 px-4 py-3">
                                    <div className="text-xs text-slate-500">Đã thu</div>
                                    <div className="font-semibold tabular-nums tracking-tight text-base whitespace-nowrap">{fmtMoney(c.paidAmount)} đ</div>
                                </div>
                                <div className="rounded-xl bg-slate-50 px-4 py-3">
                                    <div className="text-xs text-slate-500">Còn lại</div>
                                    <div className="font-semibold tabular-nums tracking-tight text-base whitespace-nowrap">{fmtMoney(c.remainingAmount)} đ</div>
                                </div>
                            </div>
                            <div className="mt-5 flex-1" />
                            <div className="mt-3 flex justify-end gap-2">
                                {canEdit ? (
                                    <>
                                        <button onClick={() => openEdit(c)} className="px-3 py-1.5 rounded-lg bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                        <button onClick={() => remove(c)} className="px-3 py-1.5 rounded-lg bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                    </>
                                ) : (
                                    <span className="text-slate-400 text-sm">Chỉ xem</span>
                                )}
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-6">
                    <div className="w-full max-w-4xl rounded-3xl bg-white shadow-2xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="text-lg font-semibold">{editing ? "Sửa hợp đồng" : "Thêm hợp đồng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>Đóng</button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Mã hợp đồng</label>
                                <input value={form.contractCode} onChange={(e) => setForm((f) => ({ ...f, contractCode: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm" placeholder="VD: HD-20250828-9154" />
                            </div>
                            {!editing && (
                                <div>
                                    <label className="text-sm text-slate-600">Khách hàng</label>
                                    <select value={form.customerId} onChange={(e) => setForm((f) => ({ ...f, customerId: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm" required>
                                        <option value="">— Chọn khách hàng —</option>
                                        {customerOptions.map((opt) => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                                    </select>
                                </div>
                            )}
                            <div>
                                <label className="text-sm text-slate-600">Phụ trách (Sale)</label>
                                <select value={form.salesId} onChange={(e) => setForm((f) => ({ ...f, salesId: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm" required>
                                    <option value="">— Chọn sale —</option>
                                    {salesOptions.map((opt) => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                                </select>
                            </div>
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Tiêu đề</label>
                                <input value={form.title} onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm" placeholder="VD: Thi công nhà xưởng B - Phase 2" />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Giá trị (đ)</label>
                                <input inputMode="numeric" value={form.totalAmount} onChange={(e) => setForm((f) => ({ ...f, totalAmount: fmtMoney(parseMoney(e.target.value)) }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm tabular-nums" placeholder="VD: 2.000.000.000" required />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Ngày ký</label>
                                <input type="date" value={form.signedDate} onChange={(e) => setForm((f) => ({ ...f, signedDate: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm" required />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Ngày hết hạn</label>
                                <input type="date" value={form.dueDate} onChange={(e) => setForm((f) => ({ ...f, dueDate: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm" />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Loại hợp đồng</label>
                                <select value={form.contractType} onChange={(e) => setForm((f) => ({ ...f, contractType: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm">
                                    {TYPE_MAP.map((t) => <option key={t.value} value={t.value}>{t.label}</option>)}
                                </select>
                            </div>
                            {editing && (
                                <div>
                                    <label className="text-sm text-slate-600">Trạng thái</label>
                                    <select value={form.status} onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))} className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm">
                                        {STATUS_MAP.map((s) => <option key={s.value} value={s.value}>{s.label}</option>)}
                                    </select>
                                </div>
                            )}
                            <div className="md:col-span-2 flex justify-end gap-2 pt-2">
                                <button type="button" className="px-3.5 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={() => setShow(false)}>Hủy</button>
                                <button className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Lưu</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

function todayStr() {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
}
function autoCode() {
    const d = new Date();
    const seg = `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, "0")}${String(d.getDate(),).padStart(2, "0")}-${Math.floor(1000 + Math.random() * 9000)}`;
    return `HD-${seg}`;
}
